    fxt = load(joinpath(FIXTURE_DIR, "fmesher_meuse_hull.jld2"))["fixture"]
    boundary = fxt["boundary"]
    params = fxt["params"]
    mesh_j = inla_mesh_2d(;
        boundary  = boundary,
        max_edge  = params["max_edge"],
        min_angle = params["min_angle"],
        cutoff    = params["cutoff"],
